import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { Accordion } from './Accordion';

const ACCORDION_ITEMS = [
  { id: 'item-1', trigger: 'Trigger 1', content: 'Content 1' },
  { id: 'item-2', trigger: 'Trigger 2', content: 'Content 2' },
  { id: 'item-3', trigger: 'Trigger 3', content: 'Content 3' },
];

describe('Accordion', () => {
  it('renders all accordion triggers', () => {
    render(<Accordion items={ACCORDION_ITEMS} />);
    ACCORDION_ITEMS.forEach((item) => {
      expect(screen.getByRole('button', { name: item.trigger })).toBeInTheDocument();
    });
  });

  it('applies roving tabindex pattern', () => {
    render(<Accordion items={ACCORDION_ITEMS} />);
    const triggers = screen.getAllByRole('button');
    // First trigger should have tabIndex 0, others should have tabIndex -1
    expect(triggers[0]).toHaveAttribute('tabindex', '0');
    expect(triggers[1]).toHaveAttribute('tabindex', '-1');
    expect(triggers[2]).toHaveAttribute('tabindex', '-1');
  });

  it('opens a panel when trigger is activated via Enter', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} />);
    const trigger = screen.getByRole('button', { name: 'Trigger 1' });

    await user.click(trigger);

    expect(screen.getByText('Content 1')).toBeVisible();
  });

  it('closes an open panel when trigger is activated again', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} />);
    const trigger = screen.getByRole('button', { name: 'Trigger 1' });

    await user.click(trigger);
    expect(screen.getByText('Content 1')).toBeVisible();

    await user.click(trigger);
    expect(screen.getByText('Content 1')).not.toBeVisible();
  });

  it('toggles aria-expanded on trigger activation', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} />);
    const trigger = screen.getByRole('button', { name: 'Trigger 1' });

    expect(trigger).toHaveAttribute('aria-expanded', 'false');

    await user.click(trigger);
    expect(trigger).toHaveAttribute('aria-expanded', 'true');

    await user.click(trigger);
    expect(trigger).toHaveAttribute('aria-expanded', 'false');
  });

  it('has aria-controls pointing to panel id', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} />);
    const trigger = screen.getByRole('button', { name: 'Trigger 1' });

    await user.click(trigger);

    const panel = screen.getByText('Content 1');
    expect(trigger).toHaveAttribute('aria-controls', panel.id);
  });

  it('moves focus with arrow keys', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} />);
    const triggers = screen.getAllByRole('button');

    triggers[0].focus();
    expect(document.activeElement).toBe(triggers[0]);

    await user.keyboard('{ArrowDown}');
    expect(document.activeElement).toBe(triggers[1]);

    await user.keyboard('{ArrowDown}');
    expect(document.activeElement).toBe(triggers[2]);
  });

  it('wraps focus with arrow keys', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} />);
    const triggers = screen.getAllByRole('button');

    triggers[2].focus();
    expect(document.activeElement).toBe(triggers[2]);

    await user.keyboard('{ArrowDown}');
    expect(document.activeElement).toBe(triggers[0]);

    await user.keyboard('{ArrowUp}');
    expect(document.activeElement).toBe(triggers[2]);
  });

  it('jumps to first trigger with Home key', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} />);
    const triggers = screen.getAllByRole('button');

    triggers[2].focus();
    await user.keyboard('{Home}');
    expect(document.activeElement).toBe(triggers[0]);
  });

  it('jumps to last trigger with End key', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} />);
    const triggers = screen.getAllByRole('button');

    triggers[0].focus();
    await user.keyboard('{End}');
    expect(document.activeElement).toBe(triggers[2]);
  });

  it('focus remains on trigger after activation', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} />);
    const trigger = screen.getByRole('button', { name: 'Trigger 1' });

    await user.click(trigger);
    expect(document.activeElement).toBe(trigger);
  });

  it('only one panel is open at a time when using exclusive mode', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} exclusive />);
    const trigger1 = screen.getByRole('button', { name: 'Trigger 1' });
    const trigger2 = screen.getByRole('button', { name: 'Trigger 2' });

    await user.click(trigger1);
    expect(screen.getByText('Content 1')).toBeVisible();

    await user.click(trigger2);
    expect(screen.getByText('Content 1')).not.toBeVisible();
    expect(screen.getByText('Content 2')).toBeVisible();
  });

  it('multiple panels can be open in non-exclusive mode', async () => {
    const user = userEvent.setup();
    render(<Accordion items={ACCORDION_ITEMS} exclusive={false} />);
    const trigger1 = screen.getByRole('button', { name: 'Trigger 1' });
    const trigger2 = screen.getByRole('button', { name: 'Trigger 2' });

    await user.click(trigger1);
    await user.click(trigger2);

    expect(screen.getByText('Content 1')).toBeVisible();
    expect(screen.getByText('Content 2')).toBeVisible();
  });
});
