import { AccordionItem, AccordionProps } from '../types/components';
import styles from '../styles/accordion.module.css';

export const Accordion: React.FC<AccordionProps> = ({
  items,
  exclusive = true,
  defaultOpen = [],
  onChange,
}) => {
  const [openIds, setOpenIds] = useState<Set<string>>(new Set(defaultOpen));
  const triggerRefs = useRef<(HTMLButtonElement | null)[]>([]);

  const isOpen = useCallback((id: string) => openIds.has(id), [openIds]);

  const toggleItem = useCallback(
    (id: string) => {
      setOpenIds((prev) => {
        const next = new Set(prev);
        if (next.has(id)) {
          next.delete(id);
        } else {
          if (exclusive) {
            next.clear();
          }
          next.add(id);
        }
        onChange?.(Array.from(next));
        return next;
      });
    },
    [exclusive, onChange]
  );

  const handleKeyDown = useCallback(
    (e: KeyboardEvent<HTMLButtonElement>, currentIndex: number) => {
      const totalItems = items.length;
      let nextIndex: number | null = null;

      switch (e.key) {
        case 'ArrowDown':
          e.preventDefault();
          nextIndex = currentIndex < totalItems - 1 ? currentIndex + 1 : 0;
          break;
        case 'ArrowUp':
          e.preventDefault();
          nextIndex = currentIndex > 0 ? currentIndex - 1 : totalItems - 1;
          break;
        case 'Home':
          e.preventDefault();
          nextIndex = 0;
          break;
        case 'End':
          e.preventDefault();
          nextIndex = totalItems - 1;
          break;
        case 'Enter':
        case ' ':
          e.preventDefault();
          toggleItem(items[currentIndex].id);
          break;
      }

      if (nextIndex !== null && nextIndex !== currentIndex) {
        triggerRefs.current[nextIndex]?.focus();
      }
    },
    [items, toggleItem]
  );

  return (
    <div className={styles.accordion} role="presentation">
      {items.map((item, index) => {
        const panelId = `accordion-panel-${item.id}`;
        const triggerId = `accordion-trigger-${item.id}`;
        const expanded = isOpen(item.id);

        return (
          <div key={item.id}>
            <button
              ref={(el) => {
                triggerRefs.current[index] = el;
              }}
              id={triggerId}
              className={styles.accordionTrigger}
              aria-expanded={expanded}
              aria-controls={panelId}
              tabIndex={index === 0 ? 0 : -1}
              onClick={() => toggleItem(item.id)}
              onKeyDown={(e) => handleKeyDown(e, index)}
              type="button"
            >
              {item.trigger}
            </button>
            <div
              id={panelId}
              className={styles.accordionPanel}
              aria-hidden={!expanded}
              role="region"
              aria-labelledby={triggerId}
            >
              {item.content}
            </div>
          </div>
        );
      })}
    </div>
  );
};
